// src/index.ts
import { ProjectType, RequestType, Producer } from "@wix/monitoring-common";

// src/factory.ts
import { createFallbackMonitoringClient } from "@wix/monitoring";

// src/client.ts
import {
  getCallLocation as getCallLocation2
} from "@wix/monitoring-common";

// src/payload-builder.ts
import { getCallLocation } from "@wix/monitoring-common";

// src/utils/id-utils.ts
var generateId = () => {
  return typeof crypto !== "undefined" && typeof crypto.randomUUID === "function" ? crypto.randomUUID() : "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, function(e) {
    const i = 16 * Math.random() | 0;
    return ("x" === e ? i : 3 & i | 8).toString(16);
  });
};

// src/utils/string-utils.ts
var stringifySafe = (value) => {
  try {
    return JSON.stringify(value);
  } catch (error) {
    return `Failed to stringify log value: ${error?.toString()}`;
  }
};

// src/payload-builder.ts
var buildBiRequestDetails = (clientParams) => {
  const {
    req,
    requestId = "",
    projectType = ProjectType.Unknown,
    requestType
  } = clientParams;
  let baseUrl = "";
  let path = "";
  if (req) {
    try {
      const url = new URL(req.url);
      baseUrl = url.origin;
      path = url.pathname;
    } catch (e) {
    }
  }
  const computedRequestType = typeof requestType === "function" ? requestType() : requestType;
  return {
    rid: requestId,
    baseUrl,
    path,
    requestType: computedRequestType ?? RequestType.Unknown,
    projectType
  };
};
var buildTelemetryPayload = (clientParams, telemetryParams) => {
  const { namespace, producer, req, requestId, hostContext } = clientParams;
  const {
    message,
    level = "INFO",
    timestamp = Date.now(),
    tags,
    contexts
  } = telemetryParams;
  const { __sourceLocation, ...restOfContext } = contexts ?? {};
  let siteUrl = "";
  if (req) {
    try {
      if (req.headers.get("referer")) {
        siteUrl = new URL(req.headers.get("referer") ?? "").origin;
      } else {
        siteUrl = new URL(req.url).origin;
      }
    } catch (e) {
    }
  }
  const messageParts = [message];
  if (tags) {
    messageParts.push(stringifySafe(tags));
  }
  if (Object.keys(restOfContext).length > 0) {
    messageParts.push(stringifySafe(restOfContext));
  }
  const sourceLocation = __sourceLocation ?? getCallLocation();
  return {
    insertId: generateId(),
    timestamp: new Date(timestamp).toISOString(),
    severity: level.toUpperCase(),
    labels: {
      tenantId: hostContext?.tenantId ?? "",
      namespace,
      ...siteUrl ? { siteUrl } : {}
    },
    operation: {
      id: requestId ?? generateId(),
      producer
    },
    ...sourceLocation ? { sourceLocation } : {},
    jsonPayload: {
      message: messageParts.join(" ")
    }
  };
};
var buildBiErrorPayload = (clientParams, biParams) => {
  const { error, contexts } = biParams;
  const requestDetails = buildBiRequestDetails(clientParams);
  let errorDetails = {
    isHandled: contexts?.errorDetails?.isHandled ?? true
  };
  if (error instanceof Error) {
    errorDetails = {
      ...errorDetails,
      errorMessage: error.message,
      errorName: error.name,
      errorStack: error.stack ?? ""
    };
  } else {
    errorDetails = {
      ...errorDetails,
      errorMessage: error?.toString() ?? "",
      errorName: "Unknown error",
      errorStack: ""
    };
  }
  return {
    src: 79,
    evid: 503,
    ...requestDetails,
    ...errorDetails
  };
};

// src/reporters/telemetry-reporter.ts
import { TELEMETRY_PATH, TELEMETRY_URL } from "@wix/monitoring-common";
var reportTelemetry = async (messages, authToken = "", fetchFn, baseUrl) => {
  const url = baseUrl ? `${baseUrl}${TELEMETRY_PATH}` : TELEMETRY_URL;
  try {
    await fetchFn(url, {
      method: "POST",
      body: JSON.stringify({ messages }),
      headers: {
        Authorization: authToken
      }
    });
  } catch (_e) {
  }
};

// src/utils/throttle.ts
var throttle = (fn, wait) => {
  let timer = null;
  const throttled = () => {
    if (timer === null) {
      timer = setTimeout(() => {
        timer = null;
        fn();
      }, wait);
    }
  };
  throttled.cancel = () => {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
  };
  return throttled;
};

// src/batch-queue.ts
var isBiEvent = (payload) => "src" in payload && "evid" in payload;
var BatchQueue = class {
  constructor(options) {
    this.options = options;
    this.queue = [];
    this.batchQueuePromise = null;
    this.resolveBatchQueuePromise = null;
    this.flushThrottled = throttle(
      () => this.flush(),
      options.throttleDuration
    );
  }
  flush() {
    const items = this.queue.splice(0);
    const payload = items.reduce(
      (res, item) => {
        if (isBiEvent(item)) {
          res.biEvents.push(item);
        } else {
          res.telemetryMessages.push(item);
        }
        return res;
      },
      { telemetryMessages: [], biEvents: [] }
    );
    this.options.flushHandler(payload).then(() => {
      this.resolveBatchQueuePromise?.();
      this.resolveBatchQueuePromise = null;
    });
    this.batchQueuePromise = null;
  }
  enqueue(...args) {
    this.queue.push(...args);
    if (!this.batchQueuePromise) {
      this.batchQueuePromise = new Promise((resolve) => {
        this.resolveBatchQueuePromise = resolve;
      });
      this.options.onBatchQueueCreated?.(this.batchQueuePromise);
    }
    if (this.queue.length === this.options.maxBatchSize) {
      this.flushThrottled.cancel();
      this.flush();
    } else {
      this.flushThrottled();
    }
  }
};

// src/utils/promise-utils.ts
var isPromise = (value) => typeof value?.then === "function";

// src/constants.ts
var MAX_BATCH_SIZE = 100;
var THROTTLE_DURATION = 300;

// src/reporters/bi-reporter.ts
import { BI_URL } from "@wix/monitoring-common";
var buildUrl = (event) => {
  const pairs = Object.entries(event).map(
    ([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`
  );
  return `${BI_URL}?${pairs.join("&")}`;
};
var reportBi = async (event, authToken = "", fetchFn) => {
  event = {
    ...event,
    _authToken: authToken
  };
  const url = buildUrl(event);
  try {
    await fetchFn(url);
  } catch (_e) {
  }
};

// src/client.ts
var VeloClient = class {
  constructor(clientParams, clientOptions = {}) {
    this.clientParams = clientParams;
    this.reportError = (captureContext = {}, error) => {
      const { tags, contexts } = captureContext;
      const payloads = [];
      payloads.push(
        buildTelemetryPayload(this.clientParams, {
          message: error?.toString() ?? "Unknown error",
          level: "error",
          tags,
          contexts: {
            __sourceLocation: getCallLocation2(error?.stack),
            ...contexts
          }
        })
      );
      if (this.reportBiOnErrors) {
        payloads.push(
          buildBiErrorPayload(this.clientParams, {
            error,
            tags,
            contexts
          })
        );
      }
      this.batchQueue.enqueue(...payloads);
    };
    this.captureException = (error, captureContext) => {
      this.reportError(captureContext, error);
    };
    this.captureMessage = (message, captureContext = {}) => {
      const { level = "info", tags, contexts } = captureContext;
      const messagePayload = buildTelemetryPayload(this.clientParams, {
        message,
        level,
        tags,
        contexts
      });
      this.batchQueue.enqueue(messagePayload);
    };
    this.startSpan = (spanOptions, callback) => {
      let res;
      try {
        res = callback();
        if (isPromise(res)) {
          res = res.then((_res) => {
            return _res;
          }).catch((e) => {
            this.reportError(spanOptions, e);
            throw e;
          });
        } else {
        }
      } catch (e) {
        this.reportError(spanOptions, e);
        throw e;
      }
      return res;
    };
    this.addBreadcrumb = (breadcrumb) => {
    };
    this.fetch = clientParams.fetch ?? globalThis.fetch;
    this.batchQueue = new BatchQueue({
      maxBatchSize: MAX_BATCH_SIZE,
      throttleDuration: THROTTLE_DURATION,
      flushHandler: (payload) => this.flushHandler(payload),
      onBatchQueueCreated: (promise) => {
        clientParams.onBatchQueueCreated?.(promise);
        const globalOnBatchQueueCreated = globalThis.__wixMonitoring?.onBatchQueueCreated;
        if (typeof globalOnBatchQueueCreated === "function") {
          globalOnBatchQueueCreated(promise);
        }
      }
    });
    this.reportBiOnErrors = clientOptions.reportErrorsToBI ?? false;
  }
  async flushHandler({
    telemetryMessages,
    biEvents
  }) {
    const { getAuthToken, baseUrl } = this.clientParams;
    const token = await getAuthToken();
    if (telemetryMessages.length > 0) {
      await reportTelemetry(telemetryMessages, token, this.fetch, baseUrl);
    }
    if (biEvents.length > 0) {
      await Promise.all(
        biEvents.map((biEvent) => reportBi(biEvent, token, this.fetch))
      );
    }
  }
  startSpanManual(spanOptions) {
    return {
      end: () => {
      },
      fail: (error) => {
        this.reportError(spanOptions, error);
      }
    };
  }
  endSpanManual(spanOptions) {
  }
};

// src/factory.ts
var createVeloMonitoringClient = (clientParams, clientOptions) => {
  const { getAuthToken } = clientParams;
  if (!getAuthToken) {
    return createFallbackMonitoringClient("Missing getAuthToken");
  }
  return new VeloClient(clientParams, clientOptions);
};
export {
  Producer,
  ProjectType,
  RequestType,
  createVeloMonitoringClient
};
