// src/monitoring-client.ts
import { createFallbackMonitoringClient } from "@wix/monitoring";
import { createSentryBrowserClient } from "@wix/monitoring-browser-sentry";
import {
  createPanoramaBrowserClient
} from "@wix/monitoring-browser-panorama";
import { createVeloMonitoringClient } from "@wix/monitoring-velo";
var isSentryConfig = (monitoringConfig) => monitoringConfig?.type === "SENTRY";
var isPanoramaConfig = (monitoringConfig) => monitoringConfig?.type === "PANORAMA";
var isWixConfig = (monitoringConfig) => monitoringConfig?.type === "WIX";
var getMonitoringClientFunction = ({
  sentrySDK,
  sentryTransport,
  panoramaClient,
  monitoringConfig,
  hostContext,
  getAuthToken,
  fetch,
  baseUrl
}) => {
  if (isSentryConfig(monitoringConfig)) {
    const { sentryOptions } = monitoringConfig;
    return () => createSentryBrowserClient({
      dsn: sentryOptions?.dsn,
      hostContext,
      sentrySDK,
      transport: sentryTransport
    });
  } else if (isPanoramaConfig(monitoringConfig)) {
    return () => createPanoramaBrowserClient({ panoramaClient });
  } else if (isWixConfig(monitoringConfig)) {
    let producer = "unknown";
    let req;
    if (typeof document !== "undefined") {
      producer = document.location.href;
      req = new Request(document.location.href);
    }
    return () => createVeloMonitoringClient(
      {
        req,
        namespace: hostContext?.platform ?? "unknown",
        producer,
        hostContext,
        getAuthToken: getAuthToken ?? (() => Promise.resolve("")),
        fetch,
        baseUrl
      },
      { reportErrorsToBI: false }
    );
  }
  return () => createFallbackMonitoringClient(
    "Invalid monitoring configuration. Please check the monitoring setup of your application."
  );
};
export {
  getMonitoringClientFunction
};
